PUT example
{
    "mappings": {
        "doc": {
            "properties": {
                "location": {
                    "type": "geo_point",
                    "ignore_malformed": true
                }
            }
        }
    }
}

PUT example/doc/1
{
  "location": "NaN,NaN"
}

PUT example/doc/2
{
  "location": "-,-"
}
```
